+#[test]
+fn index_refresh_force_alias_stays_available_for_repair_scripts() -> Result<(), String> {
+    run_on_large_stack(|| {
+        let cli = parse(&["cass", "index", "--force"])?;
+
+        match cli.command {
+            Some(Commands::Index {
+                force_rebuild: true,
+                ..
+            }) => Ok(()),
+            other => Err(format!(
+                "expected --force alias to map to force_rebuild: {other:?}"
+            )),
+        }
+    })
+}
